#!/usr/bin/env node
/**
 * Build-time step that parses `src/data/knowledge/*.md` and emits a strongly
 * typed TS module at `src/data/knowledge.generated.ts`. The edge function
 * imports the generated file, so no YAML/markdown parser ships to the
 * runtime.
 *
 * Contract per file:
 *   - YAML frontmatter with either `norad_id` (number) OR `topic` (string),
 *     plus `name`, optional `aliases`, and a `sources` array of
 *     `{ url, title }` entries.
 *   - Markdown body of 2–4 short paragraphs.
 *
 * Files whose frontmatter lacks both `norad_id` and `topic` (e.g. README)
 * are skipped.
 */

import { readdirSync, readFileSync, writeFileSync, mkdirSync } from 'node:fs'
import { dirname, join, resolve } from 'node:path'
import { fileURLToPath } from 'node:url'
import matter from 'gray-matter'

const here = dirname(fileURLToPath(import.meta.url))
const KNOWLEDGE_DIR = resolve(here, '..', 'src', 'data', 'knowledge')
// Two outputs:
//   - api/_lib: consumed by Vercel's Edge Function tsconfig. Can't import
//     across the src/ boundary. Underscore prefix keeps Vercel from
//     treating it as its own function.
//   - src/data: consumed by the React app's tsconfig (which only
//     includes "src"). Needed for SEO description generation that has to
//     run in the browser.
// Cheaper to write the file twice than to fight the tsconfig seams.
const OUTPUTS = [
  resolve(here, '..', 'api', '_lib', 'knowledge.generated.ts'),
  resolve(here, '..', 'src', 'data', 'knowledge.generated.ts'),
]

function fail(msg) {
  console.error(`[build-knowledge] ${msg}`)
  process.exit(1)
}

function validateSources(sources, file) {
  if (!Array.isArray(sources)) {
    fail(`${file}: frontmatter.sources must be an array`)
  }
  return sources.map((s, i) => {
    if (!s || typeof s.url !== 'string' || typeof s.title !== 'string') {
      fail(`${file}: sources[${i}] must be { url, title }`)
    }
    return { url: s.url, title: s.title }
  })
}

function parseEntry(fileName) {
  const full = join(KNOWLEDGE_DIR, fileName)
  const raw = readFileSync(full, 'utf8')
  const { data, content } = matter(raw)

  const hasNorad = Object.prototype.hasOwnProperty.call(data, 'norad_id')
  const hasTopic = Object.prototype.hasOwnProperty.call(data, 'topic')
  if (!hasNorad && !hasTopic) return null // skip README etc.

  if (typeof data.name !== 'string' || data.name.trim().length === 0) {
    fail(`${fileName}: missing frontmatter.name`)
  }

  const entry = {
    name: data.name.trim(),
    aliases: Array.isArray(data.aliases) ? data.aliases.map(String) : [],
    sources: validateSources(data.sources, fileName),
    body: content.trim(),
  }

  if (hasNorad) {
    if (typeof data.norad_id !== 'number' || !Number.isInteger(data.norad_id)) {
      fail(`${fileName}: norad_id must be an integer, got ${data.norad_id}`)
    }
    entry.noradId = data.norad_id
  }
  if (hasTopic) {
    if (typeof data.topic !== 'string' || data.topic.trim().length === 0) {
      fail(`${fileName}: topic must be a non-empty string`)
    }
    entry.topic = data.topic.trim()
  }

  return entry
}

function main() {
  let files
  try {
    files = readdirSync(KNOWLEDGE_DIR).filter((f) => f.endsWith('.md')).sort()
  } catch (err) {
    fail(`cannot read ${KNOWLEDGE_DIR}: ${err.message}`)
    return
  }

  const entries = []
  const seenNorad = new Map()
  const seenTopic = new Map()
  for (const f of files) {
    const entry = parseEntry(f)
    if (!entry) continue
    if (entry.noradId != null) {
      if (seenNorad.has(entry.noradId)) {
        fail(`duplicate norad_id ${entry.noradId} in ${f} and ${seenNorad.get(entry.noradId)}`)
      }
      seenNorad.set(entry.noradId, f)
    }
    if (entry.topic != null) {
      if (seenTopic.has(entry.topic)) {
        fail(`duplicate topic "${entry.topic}" in ${f} and ${seenTopic.get(entry.topic)}`)
      }
      seenTopic.set(entry.topic, f)
    }
    entries.push(entry)
  }

  for (const out of OUTPUTS) mkdirSync(dirname(out), { recursive: true })

  const header = `/**
 * AUTO-GENERATED by scripts/build-knowledge.mjs — do not edit by hand.
 * Source: src/data/knowledge/*.md
 * Regenerate with: npm run knowledge
 */

export interface KnowledgeSource {
  url: string
  title: string
}

export interface KnowledgeEntry {
  /** Present for satellite-specific entries. */
  noradId?: number
  /** Present for topic-level entries (kebab-case). */
  topic?: string
  name: string
  aliases: string[]
  sources: KnowledgeSource[]
  body: string
}

export const KNOWLEDGE: KnowledgeEntry[] = ${JSON.stringify(entries, null, 2)}

const NORAD_INDEX: Map<number, KnowledgeEntry> = new Map(
  KNOWLEDGE.filter((e): e is KnowledgeEntry & { noradId: number } => e.noradId != null).map(
    (e) => [e.noradId, e],
  ),
)

const TOPIC_INDEX: Map<string, KnowledgeEntry> = new Map(
  KNOWLEDGE.filter((e): e is KnowledgeEntry & { topic: string } => e.topic != null).map(
    (e) => [e.topic.toLowerCase(), e],
  ),
)

export function getKnowledgeByNoradId(id: number): KnowledgeEntry | null {
  return NORAD_INDEX.get(id) ?? null
}

export function getKnowledgeByTopic(topic: string): KnowledgeEntry | null {
  return TOPIC_INDEX.get(topic.toLowerCase().trim()) ?? null
}
`
  for (const out of OUTPUTS) {
    writeFileSync(out, header, 'utf8')
    console.log(`[build-knowledge] wrote ${entries.length} entries to ${out}`)
  }
}

main()
